      if respond_to?(:engine_adapter_for)
        adapter_result = engine_adapter_for(:ui).confirm(_INTL(prompt.to_s))
        return adapter_result[1] if adapter_result && adapter_result[0]
      end
      Kernel.pbConfirmMessage(_INTL(prompt.to_s))
    rescue => e
