        adapter_result = engine_adapter_for(:ui).choose_number(_INTL(prompt.to_s), params)
        return adapter_result[1] if adapter_result && adapter_result[0]
      end
      Kernel.pbMessageChooseNumber(_INTL(prompt.to_s), params)
