      "PokeDebug_Hotkeys.cfg"
    end

    def default_hotkey_config
      {
        :menu => MENU_HOTKEY,
        :walk_through_walls => WTW_HOTKEY,
        :heal_party => HEAL_HOTKEY
      }
    end

    def hotkey_choices
      [
