        "Q", "W", "E", "R", "T", "Y", "U", "I", "O", "P"
      ]
    end

    def normalize_hotkey_name(value)
      name = value.to_s.strip.upcase
      return nil if name == ""
      return nil unless hotkey_choices.include?(name)
      name
    rescue
