    def remove_party_member(pkmn)
      party = player_party
      return false if party.empty?
      if party.respond_to?(:index)
        idx = party.index(pkmn)
        return !!party.delete_at(idx) unless idx.nil?
      end
      return !!party.delete(pkmn) if party.respond_to?(:delete)
      return !!party.Delete(pkmn) if party.respond_to?(:Delete)
      false
    end

