    def event_display_name(event)
      return "Unknown Event" unless event
      event_name = event.respond_to?(:name) ? event.name.to_s : ""
      event_name = "Event #{event.id}" if event_name.strip == ""
      "#{event_name} [#{event.id}]"
    rescue => e
      log_error("Event Display Name", e)
      "Unknown Event"
    end

