        if defined?($cache) && $cache && $cache.respond_to?(:RXsystem) && $cache.RXsystem
          $cache.RXsystem
        elsif File.file?("Data/System.rxdata")
          safe_load_data("Data/System.rxdata")
        elsif File.file?("Data/System.rvdata2")
          safe_load_data("Data/System.rvdata2")
